func newTemplateSaveCmd(flags *rootFlags) *cobra.Command {
	var storeID, address, serviceMethod, itemsJSON, fromCart, description string
	cmd := &cobra.Command{
		Use:   "save <name>",
		Short: "Save a named order template",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if itemsJSON != "" && fromCart != "" {
				return fmt.Errorf("use either --items or --from-cart, not both")
			}
			name := strings.TrimSpace(args[0])
			if name == "" || strings.ContainsAny(name, `/\\: `) {
				return fmt.Errorf("template name %q contains reserved characters", args[0])
			}
			tpl := &orderTemplate{Name: name, ServiceMethod: "Delivery", Description: description, CreatedAt: time.Now().UTC()}
			if fromCart != "" {
				order, err := loadTemplateOrder(fromCart)
				if err != nil {
					return err
				}
				tpl = templateFromOrder(name, description, order)
			}
			if cmd.Flags().Changed("store") {
				tpl.StoreID = storeID
			}
			if cmd.Flags().Changed("address") {
				tpl.Address = address
			}
			if cmd.Flags().Changed("service") {
				tpl.ServiceMethod = serviceMethod
			}
			if itemsJSON != "" {
				if err := json.Unmarshal([]byte(itemsJSON), &tpl.Products); err != nil {
					return fmt.Errorf("parsing --items JSON: %w", err)
				}
			}
			if err := validateTemplate(tpl); err != nil {
				return err
			}
			if flags.dryRun {
				return writePrettyJSON(cmd.OutOrStdout(), tpl)
			}
			db, err := openTemplateStore()
			if err != nil {
				return err
			}
			defer db.Close()
			body, err := json.Marshal(tpl)
			if err != nil {
				return fmt.Errorf("marshaling template: %w", err)
			}
			if err := db.Upsert(templateResourceType, name, body); err != nil {
				return fmt.Errorf("saving template: %w", err)
			}
			if flags.asJSON {
				return flags.printJSON(cmd, tpl)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "saved template %q with %d items\n", tpl.Name, len(tpl.Products))
			return nil
		},
	}
	cmd.Flags().StringVar(&storeID, "store", "", "Store ID (e.g. 7094)")
	cmd.Flags().StringVar(&address, "address", "", "Delivery address (e.g. 421 N 63rd St, Seattle WA)")
	cmd.Flags().StringVar(&serviceMethod, "service", "Delivery", "Service method: Delivery or Carryout")
	cmd.Flags().StringVar(&itemsJSON, "items", "", "JSON array of items")
	cmd.Flags().StringVar(&fromCart, "from-cart", "", "Read a full order JSON from a cart file")
	cmd.Flags().StringVar(&description, "description", "", "Short description shown in template list")
	return cmd
}

