func loadTemplateOrder(path string) (map[string]any, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading cart file: %w", err)
	}
	var body map[string]any
	if err := json.Unmarshal(data, &body); err != nil {
		return nil, fmt.Errorf("parsing cart JSON: %w", err)
	}
	if order, ok := body["Order"].(map[string]any); ok {
		return order, nil
	}
	return body, nil
}

func templateFromOrder(name, description string, order map[string]any) *orderTemplate {
	products, _ := order["Products"].([]any)
	tpl := &orderTemplate{
		Name:          name,
		StoreID:       stringValue(order["StoreID"]),
		ServiceMethod: stringValue(order["ServiceMethod"]),
		Address:       order["Address"],
		Products:      products,
		Description:   description,
		CreatedAt:     time.Now().UTC(),
		Extras:        map[string]any{},
	}
	if payment, ok := order["Payment"].(map[string]any); ok {
		tpl.Payment = payment
	}
	for k, v := range order {
		switch k {
		case "StoreID", "ServiceMethod", "Address", "Products", "Payment", "OrderTaker":
		default:
			tpl.Extras[k] = v
		}
	}
	if len(tpl.Extras) == 0 {
		tpl.Extras = nil
	}
	if tpl.ServiceMethod == "" {
		tpl.ServiceMethod = "Delivery"
	}
	return tpl
}

func validateTemplate(tpl *orderTemplate) error {
	if strings.TrimSpace(tpl.StoreID) == "" {
		return fmt.Errorf("template requires --store or a cart with StoreID")
	}
	if tpl.Address == nil {
		return fmt.Errorf("template requires --address or a cart with Address")
	}
	if s, ok := tpl.Address.(string); ok && strings.TrimSpace(s) == "" {
		return fmt.Errorf("template requires --address or a cart with Address")
	}
	if len(tpl.Products) == 0 {
		return fmt.Errorf("template requires --items or a cart with Products")
	}
	if tpl.ServiceMethod == "" {
		tpl.ServiceMethod = "Delivery"
	}
	return nil
}

func templateOrderBody(tpl *orderTemplate, cvv string) map[string]any {
	order := map[string]any{"StoreID": tpl.StoreID, "ServiceMethod": tpl.ServiceMethod, "Address": tpl.Address, "Products": tpl.Products}
	for k, v := range tpl.Extras {
		order[k] = v
	}
	if tpl.Payment != nil {
		order["Payment"] = cloneMap(tpl.Payment)
	} else if cvv != "" {
		order["Payment"] = map[string]any{}
	}
	if payment, ok := order["Payment"].(map[string]any); ok && cvv != "" {
		payment["CVV"] = cvv
	}
	return ensureOrderTaker(order).(map[string]any)
}

func cloneMap(src map[string]any) map[string]any {
	dst := make(map[string]any, len(src))
	for k, v := range src {
		dst[k] = v
	}
	return dst
}

